SELECT documents.title, formats.format_name 
FROM documents 
JOIN formats ON documents.format_id = formats.format_id;

SELECT documents.doc_id, documents.title, themes.theme_name
FROM documents
JOIN themes ON documents.theme_id = themes.theme_id;

SELECT DISTINCT doc_id
FROM document_access
WHERE user_id = 2;

SELECT doc_id, COUNT(file_id) AS file_count
FROM document_files
GROUP BY doc_id;
